function htmlToText(value) {
  return String(value || '')
    .replace(/<\/?h[1-6][^>]*>/gi, '\n')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<\/tr>/gi, '\n')
    .replace(/<\/td>/gi, ' ')
    .replace(/<\/th>/gi, ' ')
    .replace(/<hr\s*\/?>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&#39;/g, "'")
    .replace(/&quot;/g, '"')
    .replace(/\r/g, '')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n\s+/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

async function readAttachmentText(item, itemIndex) {
  const parts = [];
  const binaryEntries = Object.entries(item.binary || {});

  for (const [propertyName, binary] of binaryEntries) {
    const fileName = String(binary.fileName || propertyName).toLowerCase();
    const mimeType = String(binary.mimeType || '').toLowerCase();
    const looksTextReport = fileName.endsWith('.xls') || fileName.endsWith('.html') || fileName.endsWith('.htm') || fileName.endsWith('.csv') || fileName.endsWith('.txt') || mimeType.includes('html') || mimeType.includes('text');

    if (!looksTextReport) continue;

    const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, propertyName);
    parts.push(buffer.toString('utf8'));
  }

  return parts.map(htmlToText).filter(Boolean).join('\n\n');
}

const output = [];

for (let index = 0; index < items.length; index += 1) {
  const item = items[index];
  const json = item.json || {};
  const emailBodyText = htmlToText(json.body?.content || json.bodyPreview || json.text || json.body || '');
  const attachmentText = await readAttachmentText.call(this, item, index);
  const bodyText = [emailBodyText, attachmentText].filter(Boolean).join('\n\n');
  const from = json.from?.emailAddress?.address || json.sender?.emailAddress?.address || json.from || null;
  const fileNames = Object.values(item.binary || {}).map((binary) => binary.fileName).filter(Boolean);

  output.push({
    json: {
      messageId: json.id || json.messageId || null,
      subject: json.subject || '',
      from,
      receivedAt: json.receivedDateTime || json.receivedAt || new Date().toISOString(),
      bodyText,
      fileName: fileNames[0] || null,
      attachmentFileNames: fileNames
    },
    binary: item.binary
  });
}

return output;

function toSeconds(value) {
  if (!value || /n\/a/i.test(String(value))) return 0;
  const text = String(value);
  const h = Number((text.match(/(\d+)\s*h/i) || [])[1] || 0);
  const m = Number((text.match(/(\d+)\s*min/i) || [])[1] || 0);
  const s = Number((text.match(/(\d+)\s*s/i) || [])[1] || 0);
  if (h || m || s) return h * 3600 + m * 60 + s;
  const hhmmss = text.match(/^(\d{1,2}):(\d{2})(?::(\d{2}))?$/);
  if (hhmmss) return Number(hhmmss[1]) * 3600 + Number(hhmmss[2]) * 60 + Number(hhmmss[3] || 0);
  return 0;
}

function num(value) {
  if (value === null || value === undefined || value === '' || /n\/a/i.test(String(value))) return null;
  const match = String(value).replace(/,/g, '').match(/-?\d+(\.\d+)?/);
  return match ? Number(match[0]) : null;
}

function readLine(block, label) {
  const escaped = label.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const re = new RegExp(`^\\s*${escaped}\\s*:\\s*(.+)$`, 'im');
  return (block.match(re) || [])[1]?.trim() || null;
}

function parseBlock(block) {
  const period = readLine(block, 'Period');
  const [periodStart, periodEnd] = period ? period.split(/\s+-\s+/) : [null, null];
  const fuelCostLine = readLine(block, 'Fuel cost') || '';

  return {
    object: readLine(block, 'Object'),
    periodStart,
    periodEnd,
    routeStart: readLine(block, 'Route start'),
    routeEnd: readLine(block, 'Route end'),
    routeLengthKm: num(readLine(block, 'Route length')),
    moveDurationSeconds: toSeconds(readLine(block, 'Move duration')),
    stopDurationSeconds: toSeconds(readLine(block, 'Stop duration')),
    stopCount: num(readLine(block, 'Stop count')) ?? 0,
    topSpeedKmh: num(readLine(block, 'Top speed')),
    averageSpeedKmh: num(readLine(block, 'Average speed')),
    overspeedCount: num(readLine(block, 'Overspeed count')) ?? 0,
    fuelConsumptionLitres: num(readLine(block, 'Fuel consumption')),
    averageFuelConsumptionPer100Km: num(readLine(block, 'Avg. fuel cons. (100 km)')),
    fuelCost: num(fuelCostLine),
    currency: fuelCostLine.match(/[A-Z]{3}/)?.[0] || 'USD',
    engineWorkSeconds: toSeconds(readLine(block, 'Engine work')),
    engineIdleSeconds: toSeconds(readLine(block, 'Engine idle')),
    odometerKm: num(readLine(block, 'Odometer')),
    engineHoursSeconds: toSeconds(readLine(block, 'Engine hours')),
    driverName: readLine(block, 'Driver') || null,
    rawData: { block }
  };
}

function parseSpreadsheetLikeRows(json) {
  const rows = Array.isArray(json.rows) ? json.rows : Array.isArray(json.records) ? json.records : [];
  return rows.map((row) => ({
    object: row.object || row.Object || row.vehicle || row.Vehicle || row['Object'],
    periodStart: row.periodStart || row['Period start'],
    periodEnd: row.periodEnd || row['Period end'],
    routeStart: row.routeStart || row['Route start'],
    routeEnd: row.routeEnd || row['Route end'],
    routeLengthKm: num(row.routeLengthKm || row['Route length'] || row['Route length km']),
    moveDurationSeconds: row.moveDurationSeconds ?? toSeconds(row['Move duration']),
    stopDurationSeconds: row.stopDurationSeconds ?? toSeconds(row['Stop duration']),
    stopCount: num(row.stopCount || row['Stop count']) ?? 0,
    topSpeedKmh: num(row.topSpeedKmh || row['Top speed']),
    averageSpeedKmh: num(row.averageSpeedKmh || row['Average speed']),
    overspeedCount: num(row.overspeedCount || row['Overspeed count']) ?? 0,
    fuelConsumptionLitres: num(row.fuelConsumptionLitres || row['Fuel consumption']),
    averageFuelConsumptionPer100Km: num(row.averageFuelConsumptionPer100Km || row['Avg. fuel cons. (100 km)']),
    fuelCost: num(row.fuelCost || row['Fuel cost']),
    currency: row.currency || row.Currency || 'USD',
    odometerKm: num(row.odometerKm || row.Odometer || row['Odometer']),
    rawData: row
  })).filter((record) => record.object);
}

return items.map((item) => {
  const json = item.json || {};
  let records = parseSpreadsheetLikeRows(json);

  if (records.length === 0) {
    const text = String(json.bodyText || '');
    const blocks = text.split(/General information/i).map((block) => block.trim()).filter(Boolean);
    records = blocks.map(parseBlock).filter((record) => record.object);
  }

  if (records.length === 0) {
    throw new Error('No EziTrack/EziMap records were parsed from the email body or rows.');
  }

  return {
    json: {
      ...json,
      records
    }
  };
});

// Keep secrets out of Code nodes. Organization id is not a secret.
const DEFAULT_ORGANIZATION_ID = 'ae975c01-c044-4c5d-b5b5-4b6a06b55957';

return items.map((item) => {
  const json = item.json || {};
  return {
    json: {
      organizationId: json.organizationId || DEFAULT_ORGANIZATION_ID,
      source: 'ezitrack_email',
      fileName: json.fileName || json.attachmentFileNames?.[0] || 'ezitrack-daily-report-email',
      emailSubject: json.subject || null,
      emailFrom: json.from || null,
      receivedAt: json.receivedAt || new Date().toISOString(),
      records: json.records || [],
      messageId: json.messageId || null
    }
  };
});

